head.script:
/**
 * 화 면 명 : 배부기준등록자동생성
 * 메뉴경로 : 회계/관리회계/실적관리/배부관리/배부기준등록
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/distmgnt/co_405_02_01p.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-10-20
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항 :
 * 수정이력 :
 *    - 2025-10-20      배기원    최초작성
 */
/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.f_Header();

    scwin.params = $c.data.getParameter();
    if (!$c.util.isEmpty(scwin.params["stdYr"])) {
        ed_stdYr.setValue(scwin.params["stdYr"]);
    }
    if (!$c.util.isEmpty(scwin.params["coCd"])) {
        ed_coCd.setValue(scwin.params["coCd"]);
    }
    if (!$c.util.isEmpty(scwin.params["coNm"])) {
        ed_coNm.setValue(scwin.params["coNm"]);
    }

    const codeOptions = [
        { grpCd: "CO007", compID: "lc_distStdCd, lc_chgDistStdCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    ed_stdYr.focus();
    $c.gus.cfDisableObjects([ed_coCd]);
};

/**
 * 조회 데이터셋 헤더 생성
 * TOBE 사용안함
 */
scwin.f_Header = function() {
    // var GAUCE_DATASET_HEADER = "coCd:STRING(3)"
    //       + ",stdYr:STRING(4)"
    //       + ",distStdCd:STRING()"
    //       + ",chgDistStdCd:STRING()";
    // ds_master.SetDataHeader(GAUCE_DATASET_HEADER);
    // ds_master.insertRow();
};

/**
 * 변경
 */
scwin.f_Change = async function (e) {
    //생성조건 입력여부 및 형식 체크
    let ret = await $c.gus.cfValidate([ed_stdYr, lc_distStdCd, lc_chgDistStdCd]);
    if (!ret) {
        return false;
    }

    if (lc_distStdCd.getValue() == lc_chgDistStdCd.getValue()) {
        await $c.win.alert("현재 기준과 변경 기준이 같습니다. 기준을 다시 선택해주세요.");
        return false;
    }
    ret = await scwin.f_chkDistributionStandardCount();
    if (!ret) {
        await $c.win.alert(lc_distStdCd.getText(true) + " 기준으로 등록된 내역이 없습니다.");
        return false;
    }
    if (await $c.win.confirm(ed_stdYr.getValue() + "년도 기준자료가 일괄 변경됩니다.<BR>"
        + lc_distStdCd.getText(true) + "기준을 " + lc_chgDistStdCd.getText(true) + "기준으로 일괄변경하시겠습니까?")) {
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);        
    }
};

// scwin.sbm_save_submiterror = function (e) {
//     $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
// };


/**
 * 현재기준 등록여부 체크
 */
scwin.f_chkDistributionStandardCount = async function () {
    var ebcId = "DistributionStandardInformationEBC";
    var queryId = "retrieveDistributionStandardCount";
    var param1 = ed_coCd.getValue();         // 회사코드
    var param2 = ed_stdYr.getValue().trim(); // 기준년도
    var param3 = lc_distStdCd.getValue();    // 현재기준
    //테스트 데이터
    //param3 = "25";
    ds_temp.removeAll();
    ds_temp.insertRow(0);
    ds_temp.setCellData(0, "sysCd"  , ebcId);
    ds_temp.setCellData(0, "queryId", queryId);
    ds_temp.setCellData(0, "param1" , param1);
    ds_temp.setCellData(0, "param2" , param2);
    ds_temp.setCellData(0, "param3" , param3);

    await $c.sbm.execute(sbm_retrieve, ds_temp.getRowJSON(0));

    if (ds_temp.getCellData(0, "col1") == "0") {
        return false;
    }else {
        return true;
    }
};

/**
 * 닫기
 */
scwin.f_WinClose = function (e) {
    let rt = ["N/A"];
    $c.win.closePopup(rt);
};
